-- ============================================================
-- FASE 3 — Schema unificado em properties (rodar no SQL editor Supabase)
-- Todas ADD COLUMN IF NOT EXISTS, nullable. Nao-destrutivo.
-- ============================================================
ALTER TABLE properties ADD COLUMN IF NOT EXISTS nome              text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS descricao         text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS descricao_curta   text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS cidade            text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS uf                text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS bairro            text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS endereco          text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS cor_acento        text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS video_url         text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS galeria           text[];
ALTER TABLE properties ADD COLUMN IF NOT EXISTS plantas           text[];
ALTER TABLE properties ADD COLUMN IF NOT EXISTS diferenciais      text[];
ALTER TABLE properties ADD COLUMN IF NOT EXISTS lazer             text[];
ALTER TABLE properties ADD COLUMN IF NOT EXISTS faq               jsonb;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS dormitorios       text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS metragem          text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS vagas             text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS suites            text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS previsao_entrega  text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS status            text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS exibir_preco      boolean DEFAULT true;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS preco             numeric;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS frase             text;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS ordem             integer;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS oculto            boolean DEFAULT false;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS ativo             boolean DEFAULT true;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS origem            text DEFAULT 'static';

-- Garantir unicidade de slug para o ON CONFLICT do upsert:
CREATE UNIQUE INDEX IF NOT EXISTS properties_slug_key ON properties (slug);

-- Verificacao das colunas:
SELECT column_name, data_type, is_nullable
FROM information_schema.columns
WHERE table_name = 'properties'
ORDER BY ordinal_position;


