ON CONFLICT (slug) DO UPDATE SET
  construtora_slug = EXCLUDED.construtora_slug,
  nome             = EXCLUDED.nome,
  cidade           = EXCLUDED.cidade,
  uf               = EXCLUDED.uf,
  bairro           = EXCLUDED.bairro,
  endereco         = EXCLUDED.endereco,
  descricao        = EXCLUDED.descricao,
  descricao_curta  = EXCLUDED.descricao_curta,
  cor_acento       = EXCLUDED.cor_acento,
  video_url        = EXCLUDED.video_url,
  galeria          = EXCLUDED.galeria,
  plantas          = EXCLUDED.plantas,
  diferenciais     = EXCLUDED.diferenciais,
  lazer            = EXCLUDED.lazer,
  faq              = EXCLUDED.faq,
  dormitorios      = EXCLUDED.dormitorios,
  metragem         = EXCLUDED.metragem,
  vagas            = EXCLUDED.vagas,
  suites           = EXCLUDED.suites,
  previsao_entrega = EXCLUDED.previsao_entrega,
  status           = EXCLUDED.status,
  origem           = 'static';
-- id, cover_image_url, book_pdf_url, ativo, oculto: preservados (nao aparecem no SET)

-- Spot-checks (1 obra, 1 pronto, 1 loteamento):
SELECT slug, nome, cidade, uf, status, dormitorios, suites, metragem, vagas, cor_acento,
       array_length(galeria,1) AS n_galeria, array_length(diferenciais,1) AS n_dif,
       array_length(lazer,1) AS n_lazer, jsonb_array_length(faq) AS n_faq,
       cover_image_url IS NOT NULL AS tem_cover, book_pdf_url IS NOT NULL AS tem_book
FROM properties
WHERE slug IN ('monte-leone-centro-criciuma-sc','calalzo-di-cadore-michel-criciuma-sc','campos-da-montanha-bom-jardim-da-serra-sc');
